const payload = $json.body || $json;

const normalize = (value) => String(value || '').toLowerCase().trim().replace(/\s+/g, '_');
const alias = {
  java: 'java_dsa',
  dsa: 'java_dsa',
  java_dsa: 'java_dsa',
  dsa_java: 'java_dsa',
  python: 'python',
  flutter: 'flutter',
  sql: 'sql'
};

const courseInput = normalize(payload.course);
const course = alias[courseInput] || courseInput;
const validCourses = ['java_dsa', 'python', 'flutter', 'sql'];

if (!course || !validCourses.includes(course)) {
  return [{
    json: {
      ok: false,
      error: 'Invalid course. Use one of: java dsa, python, flutter, sql.'
    }
  }];
}

const status = normalize(payload.status || 'done');
if (!['done', 'in_progress', 'skip'].includes(status)) {
  return [{
    json: {
      ok: false,
      error: 'Invalid status. Use: done, in_progress, or skip.'
    }
  }];
}

const minutes = Number(payload.minutes || 0);
const note = String(payload.note || '').trim();
const now = new Date();
const dateKey = now.toISOString().slice(0, 10);
const timeKey = now.toISOString();

const staticData = getWorkflowStaticData('global');
if (!staticData.days) staticData.days = {};
if (!staticData.days[dateKey]) {
  staticData.days[dateKey] = {
    courses: {},
    totalMinutes: 0,
    events: []
  };
}

const day = staticData.days[dateKey];
if (!day.courses[course]) {
  day.courses[course] = { done: 0, in_progress: 0, skip: 0, minutes: 0 };
}

day.courses[course][status] += 1;
day.courses[course].minutes += Number.isFinite(minutes) && minutes > 0 ? minutes : 0;
day.totalMinutes += Number.isFinite(minutes) && minutes > 0 ? minutes : 0;

day.events.push({
  at: timeKey,
  course,
  status,
  minutes: Number.isFinite(minutes) && minutes > 0 ? minutes : 0,
  note
});

const selectedCourses = ($env.SELECTED_COURSES || 'java dsa,python,flutter,sql')
  .split(',')
  .map((value) => normalize(value))
  .map((value) => alias[value] || value)
  .filter((value) => validCourses.includes(value));

const uniqueSelected = [...new Set(selectedCourses.length ? selectedCourses : validCourses)];
const doneCourses = uniqueSelected.filter((key) => (day.courses[key]?.done || 0) > 0);
const completionPercent = Math.round((doneCourses.length / uniqueSelected.length) * 100);

const labels = { java_dsa: 'Java DSA', python: 'Python', flutter: 'Flutter', sql: 'SQL' };
const progressLines = uniqueSelected.map((key, idx) => {
  const stats = day.courses[key] || { done: 0, in_progress: 0, skip: 0, minutes: 0 };
  return `${idx + 1}) ${labels[key]} -> done:${stats.done}, in_progress:${stats.in_progress}, skip:${stats.skip}, minutes:${stats.minutes}`;
});

const message = [
  `Live Tracker Update (${dateKey})`,
  `Completion: ${completionPercent}% (${doneCourses.length}/${uniqueSelected.length} courses touched)`,
  `Total Focus Minutes: ${day.totalMinutes}`,
  '',
  ...progressLines
].join('\n');

return [{
  json: {
    ok: true,
    date: dateKey,
    updatedCourse: course,
    status,
    minutes: Number.isFinite(minutes) && minutes > 0 ? minutes : 0,
    note,
    completionPercent,
    message
  }
}];
